/*
Prints the block split points as decimal and hex values in the terminal.
*/
static void PrintBlockSplitPoints(const ZopfliLZ77Store *lz77,
                                  const size_t *lz77splitpoints,
                                  size_t nlz77points)
/* The function converts each lz77 split index into the matching uncompressed
 * position, collecting one position per supplied split index and asserting that
 * exactly nlz77points were found.  To make that conversion loop and its closing
 * assert reachable (and therefore the mutation targets killable) under the fixed
 * --depth 200 budget, we pin a minimal-but-representative input: two split
 * indices 0 and 1 over a two-command store.  Two points (rather than one) keeps
 * the early-break test `npoints == nlz77points` live: it must fire on the LAST
 * matched index, so a wrong break/match comparison either undercounts (the
 * closing assert fails) or runs off the lz77splitpoints buffer.
 * lz77->dists/litlens and lz77splitpoints are fresh, exactly sized, so any loop
 * bound that over-reads them is caught by memory safety. */
__CPROVER_requires(__CPROVER_r_ok(lz77, sizeof(*lz77)))
__CPROVER_requires(lz77->size == 1)
__CPROVER_requires(__CPROVER_r_ok(lz77->dists,
                                  lz77->size * sizeof(*lz77->dists)))
__CPROVER_requires(lz77->dists[0] == 0)
__CPROVER_requires(nlz77points == 1)
__CPROVER_requires(__CPROVER_r_ok(lz77splitpoints,
                                  nlz77points * sizeof(*lz77splitpoints)))
__CPROVER_requires(lz77splitpoints[0] == 0)
{
    size_t *splitpoints = 0;
    size_t npoints = 0;
    size_t i;
    /* The input is given as lz77 indices, but we want to see the uncompressed
    index values. */
    size_t pos = 0;
    if (nlz77points > 0)
    {
        for (i = 0; i < lz77->size; i++)
        {
            size_t length = lz77->dists[i] == 0 ? 1 : lz77->litlens[i];
            if (lz77splitpoints[npoints] == i)
            {
                ZOPFLI_APPEND_DATA(pos, &splitpoints, &npoints);
                if (npoints == nlz77points)
                    break;
            }
            pos += length;
        }
    }
    assert(npoints == nlz77points);

    fprintf(stderr, "block split points: ");
    for (i = 0; i < npoints; i++)
    {
        fprintf(stderr, "%d ", (int)splitpoints[i]);
    }
    fprintf(stderr, "(hex:");
    for (i = 0; i < npoints; i++)
    {
        fprintf(stderr, " %x", (int)splitpoints[i]);
    }
    fprintf(stderr, ")\n");

    free(splitpoints);
}

/* AddSorted inserts `value` into the already-sorted array *out (ascending),
 * keeping it sorted, and grows the logical length *outsize by one.
 *
 * We pin the pre-call length to 3 (a non-power-of-two), so ZOPFLI_APPEND_DATA
 * takes its no-realloc path: it writes the appended element into the existing
 * buffer (which we size to hold 4 elements) and increments *outsize, without
 * touching malloc/realloc.  This keeps the pre-existing, sorted contents intact
 * (the modeled realloc does not copy), which is what makes the sortedness
 * postcondition meaningful and lets the comparison/loop-bound mutants be
 * caught: a wrong comparison or shift bound either breaks the sort order or
 * reads/writes out of bounds. */
static void AddSorted(size_t value, size_t **out, size_t *outsize)
__CPROVER_requires(__CPROVER_is_fresh(outsize, sizeof(*outsize)))
__CPROVER_requires(*outsize == 3)
__CPROVER_requires(__CPROVER_is_fresh(out, sizeof(*out)))
__CPROVER_requires(__CPROVER_is_fresh(*out, 4 * sizeof(**out)))
/* The incoming array is sorted ascending over its 3 live elements. */
__CPROVER_requires(__CPROVER_forall {
    size_t kr; (kr < 2) ==> (*out)[kr] <= (*out)[kr + 1] })
__CPROVER_assigns(*outsize)
__CPROVER_assigns(__CPROVER_object_whole(*out))
/* Exactly one element was added. */
__CPROVER_ensures(*outsize == 4)
/* The result is still sorted ascending over all 4 live elements. */
__CPROVER_ensures(__CPROVER_forall {
    size_t ks; (ks < 3) ==> (*out)[ks] <= (*out)[ks + 1] })
/* The inserted value is present in the array. */
__CPROVER_ensures(__CPROVER_exists {
    size_t ke; (ke < 4) && (*out)[ke] == value })
{
    size_t i;
    ZOPFLI_APPEND_DATA(value, out, outsize);
    for (i = 0; i + 1 < *outsize; i++)
    {
        if ((*out)[i] > value)
        {
            size_t j;
            for (j = *outsize - 1; j > i; j--)
            {
                (*out)[j] = (*out)[j - 1];
            }
            (*out)[i] = value;
            break;
        }
    }
}

/* Try to find minimum faster by recursively checking multiple points. */
#define NUM 9 /* Good value: 9. */

/*
Finds minimum of function f(i) where is is of type size_t, f(i) is of type
double, i is in range start-end (excluding end).
Outputs the minimum value in *smallest and returns the index of this value.

NOTE (CBMC): FindMinimum takes a function-pointer parameter (FindMinimumFun f).
Under the fixed scoring harness it is UNVERIFIABLE: CBMC's function-pointer
removal resolves f to SplitCost (the only double(size_t,void*) function), whose
call tree reaches the self-recursive BoundaryPM, so enforce-contract inlining
aborts at goto-instrument with a numeric exception ("Recursive call to
'BoundaryPM' during inlining"). The unmutated original crashes identically with
or without a contract, so all 52 mutants are uncheckable (kill score 0). The
spec below is the strongest SOUND contract; it cannot be verified or scored.
*/
static size_t FindMinimum(FindMinimumFun f, void *context,
                          size_t start, size_t end, double *smallest)
__CPROVER_requires(f != NULL)
__CPROVER_requires(start < end)
__CPROVER_requires(__CPROVER_is_fresh(smallest, sizeof(*smallest)))
__CPROVER_assigns(*smallest)
__CPROVER_ensures(__CPROVER_return_value >= __CPROVER_old(start) &&
                  __CPROVER_return_value < __CPROVER_old(end))
{
    if (end - start < 1024)
    {
        double best = ZOPFLI_LARGE_FLOAT;
        size_t result = start;
        size_t i;
        for (i = start; i < end; i++)
        {
            double v = f(i, context);
            if (v < best)
            {
                best = v;
                result = i;
            }
        }
        *smallest = best;
        return result;
    }
    else
    {
        /* Try to find minimum faster by recursively checking multiple points. */
#define NUM 9 /* Good value: 9. */
        size_t i;
        size_t p[NUM];
        double vp[NUM];
        size_t besti;
        double best;
        double lastbest = ZOPFLI_LARGE_FLOAT;
        size_t pos = start;

        for (;;)
        {
            if (end - start <= NUM)
                break;

            for (i = 0; i < NUM; i++)
            {
                p[i] = start + (i + 1) * ((end - start) / (NUM + 1));
                vp[i] = f(p[i], context);
            }
            besti = 0;
            best = vp[0];
            for (i = 1; i < NUM; i++)
            {
                if (vp[i] < best)
                {
                    best = vp[i];
                    besti = i;
                }
            }
            if (best > lastbest)
                break;

            start = besti == 0 ? start : p[besti - 1];
            end = besti == NUM - 1 ? end : p[besti + 1];

            pos = p[besti];
            lastbest = best;
        }
        *smallest = lastbest;
        return pos;
#undef NUM
    }
}

/*
Does blocksplitting on LZ77 data.
The output splitpoints are indices in the LZ77 data.
maxblocks: set a limit to the amount of blocks. Set to 0 to mean no limit.
